using System;
using System.Data.SqlClient;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.Azure.WebJobs;
using Microsoft.Extensions.Logging;

public static class QueryAzureSQLFunction
{
    [FunctionName("QueryAzureSQL")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger log)
    {
        string connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
        string query = req.Query["query"];
        
        if (string.IsNullOrEmpty(query))
        {
            return new BadRequestObjectResult("Query parameter is required.");
        }

        using (SqlConnection connection = new SqlConnection(connectionString))
        {
            try
            {
                await connection.OpenAsync();
                using (SqlCommand command = new SqlCommand(query, connection))
                {
                    using (SqlDataReader reader = await command.ExecuteReaderAsync())
                    {
                        var result = new System.Collections.Generic.List<System.Collections.Generic.Dictionary<string, object>>();
                        while (await reader.ReadAsync())
                        {
                            var row = new System.Collections.Generic.Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                row.Add(reader.GetName(i), reader.GetValue(i));
                            }
                            result.Add(row);
                        }

                        return new OkObjectResult(result);
                    }
                }
            }
            catch (Exception ex)
            {
                log.LogError(ex, "Error querying Azure SQL Database.");
                return new StatusCodeResult(StatusCodes.Status500InternalServerError);
